PRAGMA foreign_keys = OFF;
BEGIN IMMEDIATE;
CREATE TABLE authority_state (id INTEGER PRIMARY KEY CHECK (id = 1),auth_epoch INTEGER NOT NULL CHECK (auth_epoch > 0),updated_at TEXT NOT NULL);
CREATE TABLE device_authority_meta (schema_hash TEXT NOT NULL PRIMARY KEY,built_at TEXT NOT NULL);
CREATE TABLE device_credentials (id TEXT PRIMARY KEY,device_id TEXT NOT NULL REFERENCES devices(id),secret_hash TEXT NOT NULL,csrf_hash TEXT NOT NULL,auth_epoch INTEGER NOT NULL,created_at TEXT NOT NULL,expires_at TEXT NOT NULL,last_used_at TEXT,rotated_at TEXT,revoked_at TEXT);
CREATE TABLE devices (id TEXT PRIMARY KEY,name TEXT NOT NULL,capabilities_json TEXT NOT NULL,credential_ttl_ms INTEGER NOT NULL CHECK (credential_ttl_ms > 0),auth_epoch INTEGER NOT NULL,created_at TEXT NOT NULL,last_used_at TEXT,rotated_at TEXT,revoked_at TEXT);
CREATE TABLE pairing_grants (id TEXT PRIMARY KEY,code_hash TEXT NOT NULL,device_name TEXT NOT NULL,capabilities_json TEXT NOT NULL,credential_ttl_ms INTEGER NOT NULL CHECK (credential_ttl_ms > 0),auth_epoch INTEGER NOT NULL,created_at TEXT NOT NULL,expires_at TEXT NOT NULL,max_attempts INTEGER NOT NULL CHECK (max_attempts > 0),failed_attempts INTEGER NOT NULL DEFAULT 0,consumed_at TEXT);
