CREATE INDEX device_credentials_by_device ON device_credentials(device_id, created_at);
CREATE INDEX devices_by_revoked ON devices(revoked_at, created_at);
CREATE UNIQUE INDEX one_active_credential_per_device ON device_credentials(device_id) WHERE rotated_at IS NULL AND revoked_at IS NULL;
CREATE INDEX pairing_grants_by_expiry ON pairing_grants(consumed_at, expires_at);
COMMIT;
